    # Path: full_db_response_dict['query_db_response']['results'][0]
    raw_json_array_string_with_meta = full_db_response_dict['query_db_response']['results'][0]

    # Extract the pure JSON array string from this meta-string.
    json_array_match = re.search(r'\[.*\]', raw_json_array_string_with_meta, re.DOTALL)

    if json_array_match:
        pure_json_array_str = json_array_match.group(0)
        business_data = json.loads(pure_json_array_str)

        df_business = pd.DataFrame(business_data)

        # Function to extract the state abbreviation from the description
